type Listener = (...args: unknown[]) => void;

interface ListenerEntry {
  fn: Listener;
  once: boolean;
}

export class EventEmitter {
  private _listeners = new Map<string, ListenerEntry[]>();

  private _removeEntry(event: string, entry: ListenerEntry): void {
    const entries = this._listeners.get(event);
    if (!entries) return;
    const idx = entries.indexOf(entry);
    if (idx !== -1) entries.splice(idx, 1);
    if (entries.length === 0) this._listeners.delete(event);
  }

  // Implement: on(event, listener) - register listener, return unsubscribe function
  on(event: string, listener: Listener): () => void {
    const entry: ListenerEntry = { fn: listener, once: false };
    if (!this._listeners.has(event)) this._listeners.set(event, []);
    this._listeners.get(event)!.push(entry);
    return () => this._removeEntry(event, entry);
  }

  // Implement: once(event, listener) - listener fires only once
  once(event: string, listener: Listener): void {
    const entry: ListenerEntry = { fn: listener, once: true };
    if (!this._listeners.has(event)) this._listeners.set(event, []);
    this._listeners.get(event)!.push(entry);
  }

  // Implement: emit(event, ...args) - call all listeners, return true if any existed
  emit(event: string, ...args: unknown[]): boolean {
    const entries = this._listeners.get(event);
    if (!entries || entries.length === 0) return false;
    const snapshot = [...entries];
    for (const entry of snapshot) {
      const current = this._listeners.get(event);
      if (!current || !current.includes(entry)) continue;
      if (entry.once) this._removeEntry(event, entry);
      entry.fn(...args);
    }
    return true;
  }

  // Implement: off(event, listener) - remove specific listener
  off(event: string, listener: Listener): void {
    const entries = this._listeners.get(event);
    if (!entries) return;
    const idx = entries.findIndex(e => e.fn === listener);
    if (idx !== -1) entries.splice(idx, 1);
    if (entries.length === 0) this._listeners.delete(event);
  }

  // Implement: removeAllListeners(event?) - remove all or per-event
  removeAllListeners(event?: string): void {
    if (event === undefined) this._listeners.clear();
    else this._listeners.delete(event);
  }

  // Implement: listenerCount(event) - return count
  listenerCount(event: string): number {
    return this._listeners.get(event)?.length ?? 0;
  }

  // Implement: eventNames() - return array of events with listeners
  eventNames(): string[] {
    return [...this._listeners.keys()];
  }
}
